// src/views/user/MyProfile/composables/useModules.js
import { ref, computed } from 'vue'
import { showToast } from '@/components/ToastMessage'
import { user } from '@/api/user'
import { useProfileData } from './useProfileData'

// 所有可用的模块配置
const MODULES_CONFIG = {
  job_intention: { 
    order: 1, 
    visible: true,
    name: '求职意向',
    required: false
  },
  work_experience: { 
    order: 2, 
    visible: true,
    name: '工作经历',
    required: false
  },
  education: { 
    order: 3, 
    visible: false,
    name: '教育经历'
  },
  project: { 
    order: 4, 
    visible: false,
    name: '项目经历'
  },
  skill: { 
    order: 5, 
    visible: false,
    name: '专业技能'
  },
  certificate: { 
    order: 6, 
    visible: false,
    name: '证书奖项'
  },
  language: { 
    order: 7, 
    visible: false,
    name: '语言能力'
  },
  portfolio: { 
    order: 8, 
    visible: false,
    name: '作品展示'
  },
  social_link: { 
    order: 9, 
    visible: false,
    name: '社交主页'
  }
}

export function useModules() {
  const { fetchModuleData } = useProfileData()
  const loading = ref(false)
  const modules = ref(new Map())

  // 计算属性：激活的模块
  const activeModules = computed(() => 
    Array.from(modules.value.values())
      .filter(m => m.visible)
      .sort((a, b) => a.order - b.order)
  )

  // 计算属性：未激活的模块
  const inactiveModules = computed(() => 
    Array.from(modules.value.values())
      .filter(m => !m.visible && !m.required)
      .sort((a, b) => a.order - b.order)
  )

  // 初始化模块状态
  const initModules = () => {
    const modulesMap = new Map()
    Object.entries(MODULES_CONFIG).forEach(([key, config]) => {
      modulesMap.set(key, {
        type: key,
        name: config.name,
        order: config.order,
        visible: config.visible,
        required: config.required || false,
        data: null
      })
    })
    modules.value = modulesMap
  }

  // 获取布局和模块数据
  const fetchModulesData = async () => {
    try {
      loading.value = true

      // 1. 初始化模块状态
      if (modules.value.size === 0) {
        initModules()
      }

      // 2. 获取服务器布局
      const response = await user.getProfileLayout()
      console.log('服务器返回的布局数据:', response.data)

      if (response.data?.code === 200) {
        const serverLayout = response.data.data?.layout || {}

        // 3. 重置所有模块为默认状态
        modules.value.forEach((module, key) => {
          // 如果服务器有该模块的配置，使用服务器配置
          if (serverLayout[key]) {
            module.visible = serverLayout[key].visible
            module.order = serverLayout[key].order
          } else {
            // 如果服务器没有配置，使用默认配置
            const defaultConfig = MODULES_CONFIG[key]
            module.visible = defaultConfig.visible
            module.order = defaultConfig.order
          }
          // 重置数据
          module.data = null
        })

        // 4. 只获取激活模块的数据
        const activePromises = activeModules.value.map(async (module) => {
          try {
            const data = await fetchModuleData(module.type)
            if (data) {
              module.data = data
            }
          } catch (error) {
            console.error(`获取模块 ${module.type} 数据失败:`, error)
          }
        })

        await Promise.all(activePromises)

        console.log('处理后的模块状态:', {
          active: activeModules.value,
          inactive: inactiveModules.value
        })
      }
    } catch (error) {
      console.error('获取模块数据失败:', error)
      showToast('获取模块数据失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 移除模块
  const removeModule = async (moduleType) => {
    try {
      const module = modules.value.get(moduleType)
      if (!module || module.required) {
        throw new Error('该模块不能被移除')
      }

      loading.value = true

      // 1. 获取当前完整布局
      const layout = {}
      Object.keys(MODULES_CONFIG).forEach(key => {
        const module = modules.value.get(key)
        layout[key] = {
          order: module.order,
          visible: key === moduleType ? false : module.visible
        }
      })

      console.log('发送的布局数据:', { data: { layout } })

      // 2. 更新服务器布局
      const response = await user.updateProfileLayout({ 
        data: { layout } 
      })

      if (response.data?.code === 200) {
        // 3. 更新本地状态
        module.visible = false
        module.data = null
        showToast('模块已移除', 'success')
      }
    } catch (error) {
      console.error('移除模块失败:', error)
      showToast(error.message || '移除模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  // 添加模块
  const addModule = async (moduleType) => {
    try {
      const module = modules.value.get(moduleType)
      if (!module) {
        throw new Error('模块不存在')
      }

      loading.value = true

      // 1. 获取当前完整布局
      const layout = {}
      Object.keys(MODULES_CONFIG).forEach(key => {
        const module = modules.value.get(key)
        layout[key] = {
          order: key === moduleType ? activeModules.value.length + 1 : module.order,
          visible: key === moduleType ? true : module.visible
        }
      })

      console.log('发送的布局数据:', { data: { layout } })

      // 2. 更新服务器布局
      const response = await user.updateProfileLayout({ 
        data: { layout } 
      })

      if (response.data?.code === 200) {
        // 3. 更新本地状态
        module.visible = true
        module.order = activeModules.value.length + 1

        // 4. 获取模块数据
        module.data = await fetchModuleData(moduleType)

        showToast('模块已添加', 'success')
      }
    } catch (error) {
      console.error('添加模块失败:', error)
      showToast(error.message || '添加模块失败，请重试', 'error')
    } finally {
      loading.value = false
    }
  }

  return {
    loading,
    activeModules,
    inactiveModules,
    fetchModulesData,
    addModule,
    removeModule
  }
}
